def gradient_bg(size, top=(2,8,18), bottom=(7,26,46)):
    w,h=size; im=Image.new('RGBA',size)
    px=im.load()
    for y in range(h):
        t=y/max(1,h-1)
        c=tuple(int(top[i]*(1-t)+bottom[i]*t) for i in range(3))+(255,)
        for x in range(w): px[x,y]=c
    return im

def add_orbits(im, center, radii):
    d=ImageDraw.Draw(im,'RGBA'); cx,cy=center
    for idx,(rx,ry) in enumerate(radii):
        d.ellipse((cx-rx,cy-ry,cx+rx,cy+ry),outline=(232,194,96,70),width=2)
        for j in range(4):
            a=(idx*0.55+j*1.57)
            x=cx+int(rx*__import__('math').cos(a)); y=cy+int(ry*__import__('math').sin(a))
            d.ellipse((x-4,y-4,x+4,y+4),fill=(246,211,119,190))

def add_stars(im, n=180, seed=17):
    import random
    random.seed(seed); d=ImageDraw.Draw(im,'RGBA'); w,h=im.size
    for _ in range(n):
        x=random.randrange(w); y=random.randrange(h); r=random.choice([1,1,1,2])
        a=random.randrange(45,155)
        d.ellipse((x-r,y-r,x+r,y+r),fill=(245,214,132,a))

