def mission_detail(slug,lang):
    fr=lang=='fr'; m=MISSIONS[slug]; c=m[lang]
    old=''.join(f'<li>{x}</li>' for x in c['old']); flow=''.join(f'<div class="sequence-step"><i>{i}</i><span>{x}</span></div>' for i,x in enumerate(c['flow'],1)); graph=''.join(f'<li>{x}</li>' for x in c['graph']); metrics=''.join(f'<li>{x}</li>' for x in c['metrics'])
    related=[(s,MISSIONS[s][lang]['title']) for s in MISSIONS if s!=slug]
    rels=''.join(f'<a href="{("/proof-missions/" if fr else "/en/proof-missions/")+s}/">{t}</a>' for s,t in related)
    path=(f'/proof-missions/{slug}/' if fr else f'/en/proof-missions/{slug}/')
    title=f"{c['title']} · GoalOS"; desc=c['lead']
    main=f'''<section class="page-hero mission-hero"><div class="wrap page-hero-grid"><div><div class="eyebrow">{c['ey']} · {m['score']} {'jugement stratégique' if fr else 'strategic judgment'}</div><h1>{c['title']}</h1><p class="lead">{c['lead']}</p><div class="hero-law">{c['question']}</div><div class="actions" style="margin-top:22px"><a class="btn primary" href="{'/contact/' if fr else '/en/contact/'}">{'Proposer cet objectif' if fr else 'Nominate this objective'}</a><a class="btn dark" href="{'/proof-missions/' if fr else '/en/proof-missions/'}">{'Voir les cinq classes' if fr else 'See all five mission classes'}</a></div></div><div class="page-hero-art mission-sigil" aria-hidden="true"><div class="sigil">{m['sigil']}</div><span>{m['score']}</span></div></div></section>
<section class="section-tint"><div class="wrap"><div class="section-head"><div class="eyebrow">{'Pourquoi maintenant' if fr else 'Why now'}</div><h2>{c['question']}</h2><p>{c['why']}</p></div><div class="old-new"><article><h3>{'Ancien mode' if fr else 'Legacy mode'}</h3><ul>{old}</ul></article><div class="old-new-arrow">→</div><article><h3>GoalOS</h3><p>{'Un contrat de mission, une dette de preuve explicite, des AGI Jobs bornés, un Dossier de preuves, une revue séparée, une décision gouvernée et une capacité qui ne se propage qu’après validation.' if fr else 'A Mission Contract, explicit Proof Debt, bounded AGI Jobs, an Evidence Docket, separated review, a governed decision and capability that propagates only after validation.'}</p></article></div></div></section>
<section><div class="wrap"><div class="section-head"><div class="eyebrow">{'Chaîne d’exploitation' if fr else 'Operating chain'}</div><h2>{'Du problème à l’autorité.' if fr else 'From problem to authority.'}</h2></div><div class="sequence">{flow}</div></div></section>
<section class="section-dark"><div class="wrap"><div class="section-head"><div class="eyebrow">{'Architecture commerciale' if fr else 'Commercial architecture'}</div><h2>{c['first']}</h2><p>{'Les montants ci-dessous sont des hypothèses de lancement illustratives, pas des prix garantis, prévisions ou résultats clients.' if fr else 'The amounts below are illustrative launch hypotheses—not guaranteed prices, forecasts or customer results.'}</p></div><div class="grid grid-2"><article class="card dark-card"><h3>{'Mission initiale' if fr else 'Initial mission'}</h3><p>{c['price']}</p></article><article class="card dark-card"><h3>{'Relation récurrente' if fr else 'Recurring relationship'}</h3><p>{c['recurring']}</p></article></div></div></section>
<section><div class="wrap"><div class="grid grid-2"><article class="prose compact-prose"><h2>{'Ce qui peut entrer dans le Graphe de compétences validées' if fr else 'What may enter the Validated Skill Graph'}</h2><ul>{graph}</ul><p>{'Aucun élément n’entre automatiquement. Il doit être borné, versionné, révisé, compatible avec les droits, frais, révocable et vérifiable sous la racine autorisée.' if fr else 'Nothing enters automatically. It must be scoped, versioned, reviewed, rights-compatible, current, revocable and verifiable under the authorized root.'}</p></article><article class="prose compact-prose"><h2>{'Mesures de réalité' if fr else 'Reality metrics'}</h2><ul>{metrics}</ul><p>{'Le volume de documents et le nombre de modèles appelés ne constituent pas un résultat client.' if fr else 'Document volume and number of model calls do not constitute a customer outcome.'}</p></article></div><div class="claim-callout" style="margin-top:18px"><b>{'Frontière professionnelle et réglementaire.' if fr else 'Professional and regulatory boundary.'}</b> {c['boundary']}</div></div></section>
<section class="section-tint"><div class="wrap content-grid"><article class="prose"><h2>{'La preuve requise avant de revendiquer le produit' if fr else 'Proof required before claiming the product'}</h2><ol><li>{'Client externe et paiement encaissé.' if fr else 'External customer and collected payment.'}</li><li>{'Mission livrée selon un contrat borné.' if fr else 'Mission delivered under a bounded contract.'}</li><li>{'Résultat client mesuré avec limites d’attribution.' if fr else 'Customer outcome measured with attribution limits.'}</li><li>{'Révision indépendante appropriée au niveau de conséquence.' if fr else 'Independent review appropriate to the consequence level.'}</li><li>{'Achat répété, renouvellement ou expansion.' if fr else 'Repeat purchase, renewal or expansion.'}</li><li>{'Capacité admise puis testée sur une mission fraîche.' if fr else 'Capability admitted and then tested on a fresh mission.'}</li></ol></article><aside class="sidebar-card"><h3>{'Autres classes de missions' if fr else 'Other mission classes'}</h3>{rels}<a href="{'/proof/' if fr else '/en/proof/'}">{'État de preuve public' if fr else 'Public proof status'}</a><a href="{'/goalos-legal/' if fr else '/en/goalos-legal/'}">{'Centre juridique' if fr else 'Legal centre'}</a></aside></div></section>
<section class="section-dark"><div class="wrap"><div class="section-head"><div class="eyebrow">GoalOS</div><h2>{'Pas seulement du travail accompli. Capacité méritée. Amélioration prouvée.' if fr else 'Not merely work completed. Capability earned. Improvement proven.'}</h2></div><div class="actions"><a class="btn primary" href="{'/contact/' if fr else '/en/contact/'}">{'Proposer une mission réelle' if fr else 'Nominate a real mission'}</a><a class="btn" href="{'/goalos/' if fr else '/en/goalos/'}">{'Voir l’institution' if fr else 'See the institution'}</a></div></div></section>'''
    return shell(lang,path,title,desc,main,current=('/proof-missions/' if fr else '/en/proof-missions/'))


def portfolio_page(lang):
    fr=lang=='fr'; path='/proof-missions/' if fr else '/en/proof-missions/'
    cards=[]
    for slug,m in MISSIONS.items():
        c=m[lang]
        role={'ai-deployment':('Wedge de catégorie','Category-defining wedge'),'ai-compliance':('Couche récurrente','Recurring control layer'),'rfp-to-revenue':('Moteur de revenu','Revenue engine'),'diligence-capital':('Produit à grande valeur','High-value decision product'),'venture-office':('Laboratoire méta','Meta-institutional lab')}[slug][0 if fr else 1]
        cards.append(f'<a class="mission-card" href="{path}{slug}/"><div class="mission-card-top"><span class="mission-rank">{m["sigil"]}</span><em>{m["score"]}</em></div><h3>{c["title"]}</h3><p>{c["lead"]}</p><b>{role} →</b></a>')
    title='Missions de preuve GoalOS — Cinq classes de missions' if fr else 'GoalOS Proof Missions — Five mission classes'
    desc='Cinq classes de missions d’entreprise sur un seul GoalOS.' if fr else 'Five enterprise mission classes running on one GoalOS.'
    main=f'''<section class="page-hero mission-hero"><div class="wrap page-hero-grid"><div><div class="eyebrow">{'Cinq missions · un seul système d’exploitation' if fr else 'Five missions · one operating system'}</div><h1>{'CINQ CLASSES DE MISSIONS. UN SEUL GOALOS.' if fr else 'FIVE MISSION CLASSES. ONE GOALOS.'}</h1><p class="lead">{'Les meilleurs marchés ne sont pas ceux où l’IA écrit le document le moins cher. Ce sont ceux où elle exécute un travail coûteux — pendant que GoalOS apporte preuve, autorité, mémoire, récurrence et capacité transférable.' if fr else 'The best markets are not those where AI writes the cheapest document. They are the ones where AI executes expensive work while GoalOS supplies proof, authority, memory, recurring control and transferable capability.'}</p><div class="actions" style="margin-top:22px"><a class="btn primary" href="{'/contact/' if fr else '/en/contact/'}">{'Proposer un objectif conséquent' if fr else 'Nominate a consequential objective'}</a><a class="btn dark" href="{'/goalos/' if fr else '/en/goalos/'}">{'Explorer GoalOS' if fr else 'Explore GoalOS'}</a></div></div><div class="page-hero-art mission-sigil" aria-hidden="true"><div class="sigil">5</div><span>MISSION CLASSES</span></div></div></section>
<section class="section-tint"><div class="wrap"><div class="section-head"><div class="eyebrow">{'Portefeuille optimal' if fr else 'Optimal portfolio'}</div><h2>{'Une plateforme entre dans plusieurs marchés sans devenir cinq sociétés.' if fr else 'One platform enters several markets without becoming five companies.'}</h2><p>{'Toutes les classes utilisent les mêmes Contrats de mission, Dettes de preuve, AGI Jobs, ProofBundles, Dossiers, réviseurs, Chronique, compétences validées, droits, racines et essais successeurs.' if fr else 'Every class uses the same Mission Contracts, Proof Debt, AGI Jobs, ProofBundles, Dockets, reviewers, Chronicle, Validated Skills, entitlements, roots and successor tests.'}</p></div><div class="mission-portfolio">{''.join(cards)}</div></div></section>
<section><div class="wrap"><div class="section-head"><div class="eyebrow">{'Ordre de lancement' if fr else 'Launch order'}</div><h2>{'Trois couches dès le premier jour. Une seule visible comme phare.' if fr else 'Three layers on day one. Only one is the external flagship.'}</h2></div><div class="grid grid-3"><article class="card"><div class="icon">1</div><h3>{'Externe: Déploiement IA' if fr else 'External: AI Deployment'}</h3><p>{'Établit la catégorie, crée l’évidence client et ouvre la relation récurrente.' if fr else 'Establishes the category, creates customer evidence and opens the recurring relationship.'}</p></article><article class="card"><div class="icon">2</div><h3>{'Interne: RFP-to-Revenue' if fr else 'Internal: RFP-to-Revenue'}</h3><p>{'Vend GoalOS, prépare les propositions, relie les affirmations aux preuves et apprend des gains et pertes.' if fr else 'Sells GoalOS, prepares proposals, links claims to evidence and learns from wins and losses.'}</p></article><article class="card"><div class="icon">3</div><h3>{'Interne: Venture Office' if fr else 'Internal: Venture Office'}</h3><p>{'Teste en continu le positionnement, le prix, les segments, l’économie et les canaux de GoalOS.' if fr else 'Continuously tests GoalOS positioning, pricing, segments, economics and channels.'}</p></article></div><div class="hero-law" style="margin-top:22px">{'Après trois missions acceptées, le Bureau de conformité devient l’expansion récurrente naturelle. Après dix missions crédibles, la Salle de diligence devient un canal à grande valeur.' if fr else 'After three accepted missions, the Compliance Office becomes the natural recurring expansion. After ten credible missions, the Diligence Room becomes a high-value channel.'}</div></div></section>
<section class="section-dark"><div class="wrap"><div class="section-head"><div class="eyebrow">{'Chaîne intégrée' if fr else 'Integrated chain'}</div><h2>{'La Machine vend. La Mission prouve. Le Bureau garde la preuve vraie.' if fr else 'The Machine sells. The Mission proves. The Office keeps the proof true.'}</h2></div><div class="proof-loop"><div class="proof-step"><strong>1</strong><b>RFP-to-Revenue</b><span>{'Trouve et qualifie l’occasion.' if fr else 'Finds and qualifies the opportunity.'}</span></div><div class="proof-step"><strong>2</strong><b>{'Mission de preuve' if fr else 'Proof Mission'}</b><span>{'Rend la décision inspectable.' if fr else 'Makes the decision inspectable.'}</span></div><div class="proof-step"><strong>3</strong><b>{'Bureau de conformité' if fr else 'Compliance Office'}</b><span>{'Maintient les preuves actuelles.' if fr else 'Keeps evidence current.'}</span></div><div class="proof-step"><strong>4</strong><b>{'Diligence' if fr else 'Diligence'}</b><span>{'Ouvre partenaires, acheteurs et capital.' if fr else 'Opens partners, buyers and capital.'}</span></div><div class="proof-step"><strong>5</strong><b>{'Venture Office' if fr else 'Venture Office'}</b><span>{'Améliore toute l’institution.' if fr else 'Improves the entire institution.'}</span></div><div class="proof-step"><strong>6</strong><b>{'Chronique' if fr else 'Chronicle'}</b><span>{'Retient seulement ce qui a passé.' if fr else 'Retains only what passed.'}</span></div><div class="proof-step alert"><strong>7</strong><b>{'Mission suivante' if fr else 'Next mission'}</b><span>{'Doit devenir mesurablement meilleure.' if fr else 'Must become measurably better.'}</span></div></div></div></section>
<section><div class="wrap content-grid"><article class="prose"><h2>{'Produit fondateur' if fr else 'Founding product'}</h2><p><b>{'GoalOS Enterprise AI Proof Mission' if not fr else 'Mission de preuve IA d’entreprise GoalOS'}</b></p><p>{'Une mission bornée, un système ou une décision, une période de 10 à 20 jours ouvrables, un plan d’évaluation figé et un Dossier de preuves examinable. Les premiers partenaires peuvent recevoir une portée fondatrice à partir de 15 000 $ US; le prix normal dépend de la valeur en jeu, du niveau de preuve, de la complexité et du coût de l’erreur.' if fr else 'One bounded mission, one system or decision, a 10–20 business-day period, one frozen evaluation plan and one reviewable Evidence Docket. Founding partners may receive a narrow scope starting at US$15,000; normal pricing depends on value at stake, proof level, complexity and cost of error.'}</p><h2>{'Passage au récurrent' if fr else 'Recurring conversion'}</h2><p>{'Une mission acceptée produit déjà l’inventaire, les tests, les risques, les preuves et les conditions qui rendent un Bureau de preuve récurrent naturel.' if fr else 'An accepted mission already produces the inventory, tests, risks, evidence and conditions that make a recurring Proof Office natural.'}</p></article><aside class="sidebar-card"><h3>{'Loi commerciale' if fr else 'Commercial law'}</h3><a href="{'/proof/' if fr else '/en/proof/'}">{'Architecture → paiement → résultat → vérification → répétition → transfert' if fr else 'Architecture → payment → outcome → verification → repeat → transfer'}</a><a href="{'/downloads/' if fr else '/en/downloads/'}">{'Documents et systèmes' if fr else 'Documents and systems'}</a><a href="{'/goalos-legal/enterprise-services/' if fr else '/en/goalos-legal/enterprise-services/'}">{'Frontière des services' if fr else 'Services boundary'}</a></aside></div></section>
<section class="section-dark"><div class="wrap"><div class="section-head"><div class="eyebrow">GoalOS</div><h2>{'Le problème est réel. Le sponsor est responsable. La preuve décide.' if fr else 'The problem is real. The sponsor is accountable. Evidence decides.'}</h2></div><div class="actions"><a class="btn primary" href="{'/contact/' if fr else '/en/contact/'}">{'Proposer une mission' if fr else 'Nominate a mission'}</a><a class="btn" href="{'/frontier-masterclass/' if fr else '/en/frontier-masterclass/'}">{'Voir la MasterClass' if fr else 'See the MasterClass'}</a></div></div></section>'''
    return shell(lang,path,title,desc,main,current=path)

