def research_page(lang):
    fr=lang=='fr'; path='/research/' if fr else '/en/research/'
    src=''.join(f'''<article class="source"><b>{s['title_fr' if fr else 'title_en']}</b><span>{s['publisher']} · {s['date']}<br>{s['note_fr' if fr else 'note_en']}</span><a href="{s['url']}" rel="noopener noreferrer">{s['url']}</a></article>''' for s in SOURCES)
    main=f'''<section class="page-hero research-hero"><div class="wrap page-hero-grid"><div><div class="eyebrow">{'Contexte frontière · 20 juillet 2026' if fr else 'Frontier context · 20 July 2026'}</div><h1>{'RECHERCHE, PREUVE ET AUTORITÉ' if fr else 'RESEARCH, PROOF AND AUTHORITY'}</h1><p class="lead">{'GoalOS se situe à la convergence des agents d’entreprise, de l’évolution évaluée, de la preuve cryptographique, de la gouvernance de capacité et de l’infrastructure souveraine.' if fr else 'GoalOS sits at the convergence of enterprise agents, evaluator-driven evolution, cryptographic proof, capability governance and sovereign infrastructure.'}</p><div class="actions" style="margin-top:22px"><a class="btn primary" href="/goalos-documents/research/Merkle_Roots_for_the_Validated_Skill_Graph_v114.pdf">{'Ouvrir les notes de protocole' if fr else 'Open the protocol notes'}</a><a class="btn dark" href="{'/goalos-legal/claim-boundary/' if fr else '/en/goalos-legal/claim-boundary/'}">{'Frontière des affirmations' if fr else 'Claim boundary'}</a></div></div><div class="page-hero-art brand-hero-art" aria-hidden="true"><img src="/goalos-assets/img/brand/montreal-ai-emblem.webp" alt=""></div></div></section>
<section><div class="wrap content-grid"><article class="prose"><h2>{'Pourquoi maintenant' if fr else 'Why now'}</h2><p>{'Les agents acquièrent contexte, outils, permissions et durée. Les systèmes de recherche génèrent, exécutent, évaluent et sélectionnent des modifications. Les gouvernements structurent transparence, calcul souverain et adoption. Le goulot d’étranglement devient institutionnel : qu’est-ce qui mérite l’autorité, la mémoire, la réutilisation et le capital?' if fr else 'Agents are gaining context, tools, permissions and duration. Research systems generate, execute, evaluate and select modifications. Governments are structuring transparency, sovereign compute and adoption. The bottleneck becomes institutional: what deserves authority, memory, reuse and capital?'}</p><h2>{'Position scientifique' if fr else 'Scientific position'}</h2><p>{'Ces développements renforcent le schéma candidat → exécution → évaluation → sélection. Ils ne démontrent pas que GoalOS, une amélioration récursive générale ou une trajectoire de capacité à grande échelle ont été atteints. GoalOS propose la couche qui rend ces affirmations bornées, testables, révocables et falsifiables.' if fr else 'These developments reinforce the candidate → execution → evaluation → selection pattern. They do not demonstrate that GoalOS, general recursive improvement or large-scale capability has been achieved. GoalOS proposes the layer that makes such claims bounded, testable, revocable and falsifiable.'}</p><h2>{'Registre de sources' if fr else 'Source register'}</h2><div class="source-list">{src}</div><h2>{'Fondation GoalOS' if fr else 'GoalOS foundation'}</h2><p>{'Le Graphe de compétences validées sépare capacité privée, artéfacts de preuve, engagement cryptographique et autorité de la Chronique. Une racine Merkle rend un état compact et vérifiable; elle ne transforme pas l’inclusion en vérité. Les capacités privées peuvent rester chiffrées, hors chaîne ou dans une frontière d’exécution protégée.' if fr else 'The Validated Skill Graph separates private capability, proof artifacts, cryptographic commitment and Chronicle authority. A Merkle root makes state compact and verifiable; it does not turn inclusion into truth. Private capabilities may remain encrypted, off-chain or inside a protected execution boundary.'}</p><div class="download-list"><div class="download-item"><div><b>Merkle Roots for the Validated Skill Graph</b><span>{'Racines d’époque, mémoire Chronique, divulgation sélective et autorisation ENS.' if fr else 'Epoch roots, Chronicle memory, selective disclosure and ENS authorization.'}</span></div><a href="/goalos-documents/research/Merkle_Roots_for_the_Validated_Skill_Graph_v114.pdf">PDF</a></div><div class="download-item"><div><b>Private On-Chain Validated Skill Graph</b><span>{'Écritures agent directes, capsules chiffrées et preuve de politique à divulgation nulle.' if fr else 'Direct-agent writes, encrypted capsules and zero-knowledge policy proof.'}</span></div><a href="/goalos-documents/research/GoalOS_Private_OnChain_Validated_Skill_Graph_v97_4.pdf">PDF</a></div></div></article><aside class="sidebar-card"><h3>{'Principes de recherche' if fr else 'Research principles'}</h3><a href="{'/proof/' if fr else '/en/proof/'}">{'Préenregistrer les portes' if fr else 'Preregister the gates'}</a><a href="{'/chronicle/' if fr else '/en/chronicle/'}">{'Séparer travail et mémoire' if fr else 'Separate work and memory'}</a><a href="{'/validated-skill-graph/' if fr else '/en/validated-skill-graph/'}">{'Engager l’état, pas l’intelligence' if fr else 'Commit state, not intelligence'}</a><a href="{'/goalos-legal/claim-boundary/' if fr else '/en/goalos-legal/claim-boundary/'}">{'Publier les limites' if fr else 'Publish the limits'}</a></aside></div></section>
<section class="section-tint"><div class="wrap"><div class="section-head"><div class="eyebrow">{'Architecture visuelle' if fr else 'Visual architecture'}</div><h2>{'Concepts inspectables. Résultats non inventés.' if fr else 'Inspectable concepts. No invented results.'}</h2></div><div class="gallery"><article class="visual-card"><img src="/goalos-assets/img/private-capability-thumb.webp" alt="Private on-chain validated skill graph"><div class="body"><h3>{'Capacité privée, autorité publique' if fr else 'Private capability, public authority'}</h3><p>{'Les engagements peuvent être publics sans exposer la méthode.' if fr else 'Commitments can be public without exposing the method.'}</p><span class="ai-label">{'Visuel assisté par IA; conceptuel' if fr else 'AI-assisted visual; conceptual'}</span></div></article><article class="visual-card"><img src="/goalos-assets/img/value-dossier-thumb.webp" alt="GoalOS Value Realization Dossier"><div class="body"><h3>{'Réalisation de valeur' if fr else 'Value realization'}</h3><p>{'La valeur se mesure par la décision et le résultat, non par le volume d’output.' if fr else 'Value is measured through decisions and outcomes, not output volume.'}</p><span class="ai-label">{'Visuel assisté par IA; scénarios' if fr else 'AI-assisted visual; scenarios'}</span></div></article><article class="visual-card"><img src="/goalos-assets/img/validated-skill-graph-thumb.webp" alt="Validated Skill Graph"><div class="body"><h3>{'Mémoire de capacité' if fr else 'Capability memory'}</h3><p>{'Le graphe conserve relations, preuves, droits, versions et retours arrière.' if fr else 'The graph preserves relationships, evidence, rights, versions and rollback.'}</p><span class="ai-label">{'Visuel assisté par IA; conceptuel' if fr else 'AI-assisted visual; conceptual'}</span></div></article></div></div></section>'''
    return shell(lang,path,('Recherche GoalOS — Contexte frontière et notes de protocole' if fr else 'GoalOS Research — Frontier context and protocol notes'),('Recherche GoalOS, sources primaires, frontières des affirmations et fondation du Graphe de compétences validées.' if fr else 'GoalOS research, primary sources, claim boundaries and the Validated Skill Graph foundation.'),main,current=path)
(ROOT/'research/index.html').write_text(research_page('fr'),encoding='utf-8')
(ROOT/'en/research/index.html').write_text(research_page('en'),encoding='utf-8')

