def inject_before(text,marker,insert):
    if marker in text and insert not in text: return text.replace(marker,insert+marker,1)
    return text
home_fr=(ROOT/'index.html').read_text(encoding='utf-8')
home_en=(ROOT/'en/index.html').read_text(encoding='utf-8')
mission_cards_fr=''.join(f'<a class="mission-card" href="/proof-missions/{s}/"><div class="mission-card-top"><span class="mission-rank">{MISSIONS[s]["sigil"]}</span><em>{MISSIONS[s]["score"]}</em></div><h3>{MISSIONS[s]["fr"]["title"]}</h3><p>{MISSIONS[s]["fr"]["lead"]}</p><b>Explorer →</b></a>' for s in MISSIONS)
mission_cards_en=''.join(f'<a class="mission-card" href="/en/proof-missions/{s}/"><div class="mission-card-top"><span class="mission-rank">{MISSIONS[s]["sigil"]}</span><em>{MISSIONS[s]["score"]}</em></div><h3>{MISSIONS[s]["en"]["title"]}</h3><p>{MISSIONS[s]["en"]["lead"]}</p><b>Explore →</b></a>' for s in MISSIONS)
section_fr=f'''<section class="section-tint mission-class-section"><div class="wrap"><div class="section-head"><div class="eyebrow">Cinq classes de missions · un seul GoalOS</div><h2>Entrez par le problème le plus coûteux. Cumulez dans la même institution.</h2><p>Déploiement IA, conformité, revenu, diligence et venture utilisent le même système d’objets, de preuve, de mémoire et de transfert. Les scores sont des jugements stratégiques de gestion, pas des estimations statistiques de marché.</p></div><div class="mission-portfolio">{mission_cards_fr}</div><div class="actions" style="margin-top:22px"><a class="btn primary" href="/proof-missions/">Voir le portefeuille complet</a></div></div></section>'''
section_en=f'''<section class="section-tint mission-class-section"><div class="wrap"><div class="section-head"><div class="eyebrow">Five mission classes · one GoalOS</div><h2>Enter through the most expensive problem. Compound inside the same institution.</h2><p>AI deployment, compliance, revenue, diligence and venture use the same objects, proof, memory and transfer system. Scores are strategic management judgments—not statistical market estimates.</p></div><div class="mission-portfolio">{mission_cards_en}</div><div class="actions" style="margin-top:22px"><a class="btn primary" href="/en/proof-missions/">See the complete portfolio</a></div></div></section>'''
marker_fr='<section class="section-dark"><div class="wrap"><div class="section-head"><div class="eyebrow">Le premier cas vivant</div>'
marker_en='<section class="section-dark"><div class="wrap"><div class="section-head"><div class="eyebrow">The first living case</div>'
home_fr=inject_before(home_fr,marker_fr,section_fr)
home_en=inject_before(home_en,marker_en,section_en)
