# ---------- Global HTML upgrades ----------
for p in ROOT.rglob('*.html'):
    if 'goalos-documents/products' in p.as_posix(): continue
    text=p.read_text(encoding='utf-8')
    text=text.replace('Version publique bilingue · v1.0.0 · 2026-07-20','Version publique bilingue · v2.0.0 · 2026-07-20')
    text=text.replace('Bilingual public edition · v1.0.0 · 2026-07-20','Bilingual public edition · v2.0.0 · 2026-07-20')
    text=text.replace('Version publique v1.0.0 · En vigueur le 20 juillet 2026','Version publique v2.0.0 · En vigueur le 20 juillet 2026')
    text=text.replace('Public version v1.0.0 · Effective 20 July 2026','Public version v2.0.0 · Effective 20 July 2026')
    text=text.replace('<span class="brand-mark">G</span>','<span class="brand-mark"><img src="/goalos-assets/img/brand/montreal-ai-icon-64.png" alt=""></span>')
    soup=BeautifulSoup(text,'html.parser')
    # meta updates
    csp=soup.find('meta',attrs={'http-equiv':lambda v:v and v.lower()=='content-security-policy'})
    if csp: csp['content']=CSP
    if not soup.find('meta',attrs={'name':'referrer'}):
        m=soup.new_tag('meta'); m['name']='referrer'; m['content']='no-referrer';
        csp.insert_before(m) if csp else soup.head.append(m)
    # structured data standardized
    ld=soup.find('script',attrs={'type':'application/ld+json'})
    if ld: ld.string=ORG_JSON_TEXT
    # Theme color
    tc=soup.find('meta',attrs={'name':'theme-color'})
    if tc: tc['content']='#071a2e'
    p.write_text(str(soup),encoding='utf-8')

